# Função para remover emojis e caracteres problemáticos no Windows cp1252
def _remove_emojis(text: str) -> str:
    """Remove emojis e caracteres especiais que causam erro no terminal cp1252."""
    if not text:
        return text
    try:
        # Primeiro tenta remover através de encode/decode cp1252
        text = text.encode('cp1252', errors='ignore').decode('cp1252')
    except Exception:
        pass
    # Remove emojis e símbolos unicode (>= U+0100)
    text = re.sub(r'[\U0001F300-\U0001F9FF]|[^\x20-\x7E\xa0-\xff]', '', text)
    return text

def _should_skip_technical_log(msg: str) -> bool:
    """Retorna True se a mensagem é técnica demais para mostrar ao usuário."""
    if not msg:
        return False
    msg_lower = msg.lower()
    # Pula logs puramente técnicos
    technical_patterns = [
        'resumo 8091',
        'resumo 8117',
        'status=',
        'origem=',
        'sessão',
        'sessao',
        'criando 2',  # Criando 2ª sessão
        'reaproveitados=',
        'para_baixar=',
        'macros 8117 e 8121 detectadas',
        'macros detectadas',
        'carregado do cache',
        'ja em cache',
    ]
    return any(pattern in msg_lower for pattern in technical_patterns)

def _format_bytes_to_mb(bytes_size: int) -> str:
    """Converte bytes para MB com formatação legível."""
    mb = bytes_size / (1024 * 1024)
    if mb >= 1:
        return f"{mb:.2f} MB"
    else:
        kb = bytes_size / 1024
        return f"{kb:.2f} KB"

